mapper.select:
select 
from source_files
where source_id = #{sourceId}
  and relative_path = #{relativePath}

with query as ( select plainto_tsquery(cast(#{tsConfig} as regconfig), #{question}) as tsq ) select sf.source_id, sf.file_path as item_key, sf.file_path as concept_id, sf.relative_path as title, sf.content_text as content, sf.metadata_json::text as metadata_json, array[sf.file_path]::text[] as source_paths, null::integer as chunk_index, sf.is_verbatim as verbatim, ts_rank_cd(sf.search_tsv, query.tsq)
+ case when sf.file_path_norm like #{likeToken} then 4.0 else 0 end + case when lower(sf.content_preview) like #{likeToken} then 1.5 else 0 end + case when lower(sf.content_text) like #{likeToken} then 1.0 else 0 end
as score from source_files sf cross join query where sf.search_tsv @@ query.tsq
or sf.file_path_norm like #{likeToken} or lower(sf.content_preview) like #{likeToken} or lower(sf.content_text) like #{likeToken}
order by score desc, sf.indexed_at desc, sf.relative_path asc, sf.file_path asc limit #{limit}
